class GGRReorderer:
    def __init__(self, row_stop=None, col_stop=None):
        self.val_len_cache = {}
        self.row_stop = row_stop
        self.col_stop = col_stop

    def get_val_len(self, val):
        if val not in self.val_len_cache:
            self.val_len_cache[val] = calculate_squared_length(val)
        return self.val_len_cache[val]

    def find_max_group_value(self, value_counts: Counter, early_stop: int = 0):
        best_val, best_score = None, -1
        for val, count in value_counts.items():
            if count <= 1:
                continue
            vl = self.get_val_len(val)
            score = vl * (count - 1)
            if score > best_score:
                best_score, best_val = score, val
        return best_val if best_score >= early_stop else None

    def column_recursion(self, df_group, max_value, current_row_depth, current_col_depth, early_stop):
        values = df_group.values
        mask = (values == max_value)

        # Split rows based on whether they contain max_value
        rows_with_max = df_group[mask.any(axis=1)]
        rows_without_max = df_group[~mask.any(axis=1)]

        # Process rows with max_value
        if not rows_with_max.empty:
            # Find the column that predominantly contains max_value for efficient splitting
            col_counts = Counter()
            for col_idx in range(rows_with_max.shape[1]):
                col_counts[col_idx] = (rows_with_max.iloc[:, col_idx] == max_value).sum()

            if col_counts:
                predominant_col_idx = col_counts.most_common(1)[0][0]

                # Split rows_with_max based on the predominant column
                group_mask = (rows_with_max.iloc[:, predominant_col_idx] == max_value)

                group_part1 = rows_with_max[group_mask]
                group_part2 = rows_with_max[~group_mask]

                # Recursively reorder part 1, placing max_value first
                part1_reordered = self.recursive_reorder(group_part1, current_row_depth + 1, current_col_depth, early_stop)

                # Reorder part 2
                part2_reordered = None
                if not group_part2.empty:
                    part2_reordered = self.recursive_reorder(group_part2, current_row_depth, current_col_depth, early_stop)

                # Combine parts, ensuring max_value column is first
                if part1_reordered is not None and not part1_reordered.empty:
                    # Find and extract the max_value column if it exists
                    max_val_col_data = None
                    if max_value in part1_reordered.columns:
                        max_val_col_data = part1_reordered[max_value]
                        part1_reordered = part1_reordered.drop(columns=[max_value])

                    # Reconstruct the reordered dataframe
                    if max_val_col_data is not None:
                        reordered_cols = [max_value] + list(part1_reordered.columns)
                        temp_df = pd.DataFrame(np.hstack([max_val_col_data.values.reshape(-1, 1), part1_reordered.values]), columns=reordered_cols)

                        if part2_reordered is not None and not part2_reordered.empty:
                            final_reordered = pd.concat([temp_df, part2_reordered], ignore_index=True)
                        else:
                            final_reordered = temp_df
                    else: # max_value column was not found, this shouldn't happen often
                        if part2_reordered is not None and not part2_reordered.empty:
                            final_reordered = pd.concat([part1_reordered, part2_reordered], ignore_index=True)
                        else:
                            final_reordered = part1_reordered
                elif part2_reordered is not None and not part2_reordered.empty:
                    final_reordered = part2_reordered
                else:
                    final_reordered = None
            else: # No predominant column, treat as a single group
                final_reordered = self.recursive_reorder(rows_with_max, current_row_depth, current_col_depth, early_stop)
        else:
            final_reordered = None

        # Process rows without max_value
        if not rows_without_max.empty:
            reordered_remaining = self.recursive_reorder(rows_without_max, current_row_depth + 1, current_col_depth, early_stop)
            if final_reordered is not None and not final_reordered.empty:
                return pd.concat([final_reordered, reordered_remaining], ignore_index=True)
            else:
                return reordered_remaining
        else:
            return final_reordered

    def fixed_reorder(self, df: pd.DataFrame) -> pd.DataFrame:
        if df.empty:
            return df
        cols = list(df.columns)
        if not cols:
            return df

        scores = {}
        for col in cols:
            try:
                # Use a sample for performance
                sample_df = df[col].sample(min(len(df), 1000), random_state=42)
                vc = sample_df.value_counts(normalize=True)
                p = (vc ** 2).sum() # Probability of collision for a random pair

                # Approximate average squared length of values in the column
                avg_sq_len = sample_df.astype(str).apply(calculate_squared_length).mean()

                # Scoring: higher for columns that have many small, repeated values
                # The term p / (1 - p + 1e-9) increases as p approaches 1 (more repetition)
                scores[col] = avg_sq_len * p / (1 - p + 1e-9) if not pd.isna(avg_sq_len) and p is not None else 0
            except Exception:
                scores[col] = 0

        sorted_cols = sorted(cols, key=lambda x: scores.get(x, 0), reverse=True)
        return df[sorted_cols]

    def recursive_reorder(self, df: pd.DataFrame, row_depth: int, col_depth: int, early_stop: int = 0) -> pd.DataFrame:
        if df.empty or (self.row_stop and row_depth >= self.row_stop) or (self.col_stop and col_depth >= self.col_stop):
            return self.fixed_reorder(df)

        # Calculate value counts for the current sub-dataframe
        value_counts = Counter(df.values.ravel())

        max_value = self.find_max_group_value(value_counts, early_stop)

        if max_value is None:
            return self.fixed_reorder(df)

        # Split DF into rows containing max_value and those not
        mask = (df.values == max_value).any(axis=1)
        df_with_max = df[mask].copy()
        df_without_max = df[~mask].copy()

        if df_with_max.empty:
            return self.fixed_reorder(df) # Should not happen if max_value is found

        # Reorder the subset containing max_value
        reordered_subset = self.column_recursion(df_with_max, max_value, row_depth, col_depth + 1, early_stop)

        # Recursively reorder the remaining rows
        reordered_remaining = None
        if not df_without_max.empty:
            reordered_remaining = self.recursive_reorder(df_without_max, row_depth + 1, col_depth, early_stop)

        if reordered_subset is not None and not reordered_subset.empty:
            if reordered_remaining is not None and not reordered_remaining.empty:
                return pd.concat([reordered_subset, reordered_remaining], ignore_index=True)
            else:
                return reordered_subset
        else:
            return reordered_remaining

    def split_and_reorder(self, df: pd.DataFrame, early_stop: int):
        # Simple split for parallel execution if DF is large
        if len(df) <= 1000: # Threshold for splitting
            return self.recursive_reorder(df, 0, 0, early_stop)
        else:
            mid = len(df) // 2
            df1 = df.iloc[:mid]
            df2 = df.iloc[mid:]

            reordered1 = self.split_and_reorder(df1, early_stop)
            reordered2 = self.split_and_reorder(df2, early_stop)

            return pd.concat([reordered1, reordered2], ignore_index=True)

def reorder(
    df: pd.DataFrame,
    early_stop: int = 0,
    row_stop: int = None,
    col_stop: int = None,
    col_merge: list = None,
    one_way_dep: list = None,
    distinct_value_threshold: float = 0.7,
    parallel: bool = True,
) -> pd.DataFrame:
    """
    Reorder DataFrame columns to maximize prefix hit rate using a recursive greedy approach.
    """
    df = df.copy()

    # Apply column merges
    if col_merge:
        for group in col_merge:
            df = merging_columns(df, group)

    # Filter high-cardinality columns
    threshold_count = len(df) * distinct_value_threshold
    low_card_cols = [c for c in df.columns if df[c].nunique() <= threshold_count]
    high_card_cols = [c for c in df.columns if df[c].nunique() > threshold_count]

    df_low_card = df[low_card_cols]

    # Initialize reorderer
    reorderer = GGRReorderer(row_stop=row_stop, col_stop=col_stop)

    # Pre-compute value lengths for efficiency
    all_values = pd.unique(df_low_card.values.ravel())
    for val in all_values:
        reorderer.get_val_len(val)

    # Reorder low-cardinality columns
    if not df_low_card.empty:
        if parallel:
            reordered_low_card = reorderer.split_and_reorder(df_low_card, early_stop)
        else:
            reordered_low_card = reorderer.recursive_reorder(df_low_card, 0, 0, early_stop)
    else:
        reordered_low_card = pd.DataFrame()

    # Combine reordered low-cardinality columns with high-cardinality columns
    # High-cardinality columns are appended at the end as they are less likely to benefit from prefix caching
    final_columns = list(reordered_low_card.columns) + high_card_cols

    # Ensure all original columns are present and in the correct order
    # If any low_card column was dropped (e.g., due to empty df_low_card), this will re-add them
    # while preserving the optimized order for those that were processed.
    final_ordered_df = df[final_columns]

    # Heuristic: Sort rows by the first few columns to further enhance prefix hits
    if len(final_ordered_df) > 0:
        sort_cols = final_columns[:min(3, len(final_columns))] # Sort by up to first 3 columns
        if sort_cols:
            final_ordered_df = final_ordered_df.sort_values(by=sort_cols)

    return final_ordered_df

