def compute_column_score(col_series, sample_size=2000):
    """Compute score for a column based on its value distribution and lengths."""
    if len(col_series) > sample_size:
        sample = col_series.sample(sample_size, random_state=42)
    else:
        sample = col_series

    # Compute value frequencies
    value_counts = sample.value_counts()
    total = len(sample)

    if total == 0:
        return 0.0

    # Calculate probability that two random rows have the same value
    p_same = ((value_counts / total) ** 2).sum()

    # Estimate average squared length
    if col_series.dtype == 'object':
        # For string columns, sample lengths
        str_sample = sample.dropna().astype(str)
        if len(str_sample) > 0:
            avg_sq_len = (str_sample.str.len() ** 2).mean()
        else:
            avg_sq_len = 0
    else:
        # For numeric columns, estimate length
        avg_sq_len = calculate_squared_length(sample.iloc[0]) if len(sample) > 0 else 0

    # Score favors columns with high repetition and moderate length
    # Using a balanced formula that considers both factors
    if p_same > 0.99:
        return avg_sq_len * 100  # Very high repetition
    elif p_same > 0:
        return avg_sq_len * (p_same / (1 - p_same + 1e-9))
    else:
        return avg_sq_len * 0.01

class PrefixOptimizer:
    def __init__(self, row_stop=None, col_stop=None, parallel=False):
        self.row_stop = row_stop
        self.col_stop = col_stop
        self.parallel = parallel
        self.value_len_cache = {}

    def get_value_length(self, value):
        """Get cached squared length of a value."""
        if value not in self.value_len_cache:
            self.value_len_cache[value] = calculate_squared_length(value)
        return self.value_len_cache[value]

    def evaluate_prefix_hit(self, df, col_order):
        """Evaluate prefix hit score for a given column order."""
        if len(df) <= 1:
            return 0

        total_score = 0
        prev_row = None

        # Convert to string representation for each row
        for _, row in df[col_order].iterrows():
            current_str = ''.join(str(val) for val in row)
            if prev_row is not None:
                # Find common prefix
                common_len = 0
                min_len = min(len(prev_row), len(current_str))
                for i in range(min_len):
                    if prev_row[i] == current_str[i]:
                        common_len += 1
                    else:
                        break
                if common_len > 0:
                    total_score += common_len ** 2
            prev_row = current_str

        return total_score

    def greedy_column_ordering(self, df, early_stop=0):
        """Greedy algorithm to find good column ordering."""
        if df.empty or len(df.columns) <= 1:
            return list(df.columns)

        remaining_cols = set(df.columns)
        ordered_cols = []

        # Compute initial scores for all columns
        col_scores = {}
        for col in remaining_cols:
            col_scores[col] = compute_column_score(df[col])

        # Start with the column with highest score
        current_col = max(col_scores, key=col_scores.get)
        ordered_cols.append(current_col)
        remaining_cols.remove(current_col)

        # Greedily add columns that maximize prefix hits
        while remaining_cols:
            best_col = None
            best_score = -1

            # Try each remaining column in the next position
            for col in remaining_cols:
                test_order = ordered_cols + [col]
                score = self.evaluate_prefix_hit(df.sample(min(1000, len(df))), test_order)

                if score > best_score:
                    best_score = score
                    best_col = col

            if best_col is None or best_score < early_stop:
                # Add remaining columns by their individual scores
                remaining_sorted = sorted(remaining_cols, key=lambda x: col_scores[x], reverse=True)
                ordered_cols.extend(remaining_sorted)
                break

            ordered_cols.append(best_col)
            remaining_cols.remove(best_col)

        return ordered_cols

    def cluster_similar_columns(self, df, sample_size=1000):
        """Cluster columns based on value similarity."""
        if len(df.columns) <= 1:
            return [list(df.columns)]

        # Sample data for efficiency
        if len(df) > sample_size:
            sample_df = df.sample(sample_size, random_state=42)
        else:
            sample_df = df

        # Compute pairwise similarity between columns
        similarities = {}
        cols = list(df.columns)

        for i in range(len(cols)):
            for j in range(i + 1, len(cols)):
                col1, col2 = cols[i], cols[j]

                # Simple similarity measure: fraction of rows with same values
                if len(sample_df) > 0:
                    same_count = (sample_df[col1] == sample_df[col2]).sum()
                    similarity = same_count / len(sample_df)
                else:
                    similarity = 0

                if similarity > 0.3:  # Threshold for similarity
                    similarities[(col1, col2)] = similarity

        # Simple clustering: group columns with high similarity
        clusters = []
        unassigned = set(cols)

        while unassigned:
            col = unassigned.pop()
            cluster = [col]

            # Find similar columns
            for other_col in list(unassigned):
                pair = tuple(sorted([col, other_col]))
                if pair in similarities and similarities[pair] > 0.5:
                    cluster.append(other_col)
                    unassigned.remove(other_col)

            clusters.append(cluster)

        return clusters

    def optimize_with_clustering(self, df, early_stop=0):
        """Optimize column order using clustering."""
        # Cluster similar columns
        clusters = self.cluster_similar_columns(df)

        # Optimize order within each cluster
        ordered_clusters = []
        for cluster in clusters:
            if len(cluster) > 1:
                # Optimize order within cluster
                cluster_df = df[cluster]
                cluster_order = self.greedy_column_ordering(cluster_df, early_stop)
                ordered_clusters.append(cluster_order)
            else:
                ordered_clusters.append(cluster)

        # Optimize order between clusters
        if len(ordered_clusters) > 1:
            # Create representative data for each cluster
            cluster_reps = []
            for cluster in ordered_clusters:
                # Use first column as representative
                if cluster:
                    cluster_reps.append(cluster[0])

            # Create a simplified DataFrame for cluster ordering
            rep_df = df[cluster_reps]
            cluster_order_indices = self.greedy_column_ordering(rep_df, early_stop)

            # Map back to original columns
            cluster_dict = {rep: cluster for rep, cluster in zip(cluster_reps, ordered_clusters)}
            final_order = []
            for rep in cluster_order_indices:
                final_order.extend(cluster_dict[rep])

            return final_order
        else:
            return ordered_clusters[0] if ordered_clusters else []

    def reorder_dataframe(self, df, early_stop=0):
        """Main reordering function."""
        if df.empty or len(df.columns) <= 1:
            return df

        # First, sort rows by all columns to maximize prefix hits
        sorted_df = df.sort_values(by=list(df.columns))

        # Get optimized column order
        if len(df.columns) <= 10:
            # For small number of columns, use greedy ordering
            col_order = self.greedy_column_ordering(sorted_df, early_stop)
        else:
            # For larger number of columns, use clustering approach
            col_order = self.optimize_with_clustering(sorted_df, early_stop)

        # Ensure we have all columns
        if set(col_order) != set(df.columns):
            missing = set(df.columns) - set(col_order)
            col_order.extend(missing)

        return sorted_df[col_order]

def reorder(
    df: pd.DataFrame,
    early_stop: int = 0,
    row_stop: int = None,
    col_stop: int = None,
    col_merge: list = None,
    one_way_dep: list = None,
    distinct_value_threshold: float = 0.7,
    parallel: bool = True,
) -> pd.DataFrame:
    """
    Reorder DataFrame columns to maximize prefix hit rate.
    """
    df = df.copy()

    # Apply column merges if specified
    if col_merge:
        for group in col_merge:
            df = merging_columns(df, group)

    # Filter out high-cardinality columns (they go to the end)
    threshold_count = len(df) * distinct_value_threshold
    low_card_cols = [c for c in df.columns if df[c].nunique() <= threshold_count]
    high_card_cols = [c for c in df.columns if df[c].nunique() > threshold_count]

    # Optimize low-cardinality columns
    optimizer = PrefixOptimizer(row_stop=row_stop, col_stop=col_stop, parallel=parallel)

    if low_card_cols:
        low_card_df = df[low_card_cols]
        optimized_low_card = optimizer.reorder_dataframe(low_card_df, early_stop)

        # Combine with high-cardinality columns
        final_order = list(optimized_low_card.columns) + high_card_cols
    else:
        final_order = list(df.columns)

    # Sort rows by the final column order to maximize prefix hits
    result = df[final_order].sort_values(by=final_order[:min(3, len(final_order))])

    return result
